function twoSum(nums, target) {
  const map = new Map(); // Stores { value => index }
  for (let i = 0; i < nums.length; i++) {
    const complement = target - nums[i];
    if (map.has(complement)) {
      return [map.get(complement), i];
    }
    map.set(nums[i], i);
  }
  return [];
  // Time Complexity: O(N) - single pass scan
  // Space Complexity: O(N) - stores elements in map
}

function maxSubArray(nums) {
  let maxSoFar = nums[0];
  let currentMax = nums[0];
  for (let i = 1; i < nums.length; i++) {
    // Greedy choice: extend current subarray or start a new one
    currentMax = Math.max(nums[i], currentMax + nums[i]);
    maxSoFar = Math.max(maxSoFar, currentMax);
  }
  return maxSoFar;
  // Time Complexity: O(N) - single pass loop
  // Space Complexity: O(1) - constant variables used
}

function maxArea(height) {
  let maxWater = 0;
  let left = 0;
  let right = height.length - 1;
  while (left < right) {
    const width = right - left;
    const currentHeight = Math.min(height[left], height[right]);
    const area = width * currentHeight;
    maxWater = Math.max(maxWater, area);

    // Move the shorter line inward
    if (height[left] < height[right]) {
      left++;
    } else {
      right--;
    }
  }
  return maxWater;
  // Time Complexity: O(N) - pointers meet in the middle
  // Space Complexity: O(1) - only primitive pointers
}

function isPalindrome(s) {
  let left = 0;
  let right = s.length - 1;
  const isAlphanumeric = (c) => /[a-zA-Z0-9]/.test(c);

  while (left < right) {
    while (left < right && !isAlphanumeric(s[left])) left++;
    while (left < right && !isAlphanumeric(s[right])) right--;

    if (s[left].toLowerCase() !== s[right].toLowerCase()) {
      return false;
    }
    left++;
    right--;
  }
  return true;
  // Time Complexity: O(N) - single scan of the string
  // Space Complexity: O(1) - in-place pointers, no new string created
}

function lengthOfLongestSubstring(s) {
  let maxLen = 0;
  let left = 0;
  const charMap = new Map(); // Stores { character => index }

  for (let right = 0; right < s.length; right++) {
    const char = s[right];
    if (charMap.has(char) && charMap.get(char) >= left) {
      // Shrink window past duplicate character
      left = charMap.get(char) + 1;
    }
    charMap.set(char, right);
    maxLen = Math.max(maxLen, right - left + 1);
  }
  return maxLen;
  // Time Complexity: O(N) - sliding window slides right once
  // Space Complexity: O(min(M, N)) - size of alphabet map
}

function minWindow(s, t) {
  if (s.length < t.length) return '';
  const tFreq = {};
  for (let char of t) tFreq[char] = (tFreq[char] || 0) + 1;

  const windowFreq = {};
  let left = 0, right = 0;
  let required = Object.keys(tFreq).length;
  let formed = 0;
  let minLen = Infinity, minStart = 0;

  while (right < s.length) {
    const char = s[right];
    windowFreq[char] = (windowFreq[char] || 0) + 1;
    if (tFreq[char] && windowFreq[char] === tFreq[char]) {
      formed++;
    }

    while (left <= right && formed === required) {
      const curLen = right - left + 1;
      if (curLen < minLen) {
        minLen = curLen;
        minStart = left;
      }
      const lChar = s[left];
      windowFreq[lChar]--;
      if (tFreq[lChar] && windowFreq[lChar] < tFreq[lChar]) {
        formed--;
      }
      left++;
    }
    right++;
  }
  return minLen === Infinity ? '' : s.substring(minStart, minStart + minLen);
  // Time Complexity: O(S + T) - S and T are strings lengths
  // Space Complexity: O(S + T) - frequency maps
}

function reverseList(head) {
  let prev = null;
  let curr = head;
  while (curr !== null) {
    const nextTemp = curr.next; // Store next node temporarily
    curr.next = prev;           // Reverse pointer direction
    prev = curr;                // Move prev pointer forward
    curr = nextTemp;            // Move curr pointer forward
  }
  return prev; // New head of reversed list
  // Time Complexity: O(N) - single pass traversing N nodes
  // Space Complexity: O(1) - in-place variable changes
}

function removeNthFromEnd(head, n) {
  const dummy = new ListNode(0, head);
  let fast = dummy;
  let slow = dummy;

  // Advance fast pointer N+1 steps to create gap
  for (let i = 0; i <= n; i++) {
    fast = fast.next;
  }

  // Move both pointers until fast reaches end
  while (fast !== null) {
    fast = fast.next;
    slow = slow.next;
  }

  // Remove Nth node
  slow.next = slow.next.next;
  return dummy.next;
  // Time Complexity: O(N) - single traversal
  // Space Complexity: O(1) - constant overhead
}

function maxDepth(root) {
  if (root === null) return 0; // Base Case
  const leftDepth = maxDepth(root.left);
  const rightDepth = maxDepth(root.right);
  return Math.max(leftDepth, rightDepth) + 1;
  // Time Complexity: O(N) - visits every node once
  // Space Complexity: O(H) - call stack height (H is tree height)
}

function invertTree(root) {
  if (root === null) return null;

  // Swap left and right child nodes
  const temp = root.left;
  root.left = root.right;
  root.right = temp;

  // Recursively swap subtrees
  invertTree(root.left);
  invertTree(root.right);

  return root;
  // Time Complexity: O(N) - visits every node once
  // Space Complexity: O(H) - recursion call stack
}

function levelOrder(root) {
  if (!root) return [];
  const result = [];
  const queue = [root]; // Queue initialized with root

  while (queue.length > 0) {
    const levelSize = queue.length;
    const currentLevel = [];

    for (let i = 0; i < levelSize; i++) {
      const node = queue.shift(); // Remove from front
      currentLevel.push(node.val);

      if (node.left) queue.push(node.left);  // Add left to back
      if (node.right) queue.push(node.right); // Add right to back
    }
    result.push(currentLevel);
  }
  return result;
  // Time Complexity: O(N) - visits every node once
  // Space Complexity: O(N) - queue storage size (up to N/2 nodes at max depth)
}

function isValidBST(root) {
  return validate(root, null, null);
}

function validate(node, min, max) {
  if (node === null) return true;

  // Check if current value violates min/max boundaries
  if ((min !== null && node.val <= min) || (max !== null && node.val >= max)) {
    return false;
  }

  // Recursively validate left and right children with updated ranges
  return (
    validate(node.left, min, node.val) &&
    validate(node.right, node.val, max)
  );
  // Time Complexity: O(N) - checks all nodes
  // Space Complexity: O(H) - stack frames up to tree height
}

function numIslands(grid) {
  if (!grid || grid.length === 0) return 0;
  let count = 0;
  const rows = grid.length;
  const cols = grid[0].length;

  function dfs(r, c) {
    // Base check: bounds and water filter
    if (r < 0 || c < 0 || r >= rows || c >= cols || grid[r][c] === '0') {
      return;
    }
    grid[r][c] = '0'; // Sink element (marks as visited)

    // Explore adjacent directions
    dfs(r + 1, c);
    dfs(r - 1, c);
    dfs(r, c + 1);
    dfs(r, c - 1);
  }

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      if (grid[r][c] === '1') {
        count++;
        dfs(r, c);
      }
    }
  }
  return count;
  // Time Complexity: O(R * C) - visits every cell at most twice
  // Space Complexity: O(R * C) - recursion stack worst case if grid is all land
}

function canFinish(numCourses, prerequisites) {
  const adjList = Array.from({ length: numCourses }, () => []);
  const inDegree = new Array(numCourses).fill(0);

  // Build graph and calculate indegrees
  for (let [course, prereq] of prerequisites) {
    adjList[prereq].push(course);
    inDegree[course]++;
  }

  const queue = [];
  for (let i = 0; i < numCourses; i++) {
    if (inDegree[i] === 0) queue.push(i);
  }

  let processedCount = 0;
  while (queue.length > 0) {
    const course = queue.shift();
    processedCount++;

    for (let neighbor of adjList[course]) {
      inDegree[neighbor]--;
      if (inDegree[neighbor] === 0) {
        queue.push(neighbor);
      }
    }
  }
  return processedCount === numCourses;
  // Time Complexity: O(V + E) - traversing vertices and edges
  // Space Complexity: O(V + E) - graph storage lists
}

function ladderLength(beginWord, endWord, wordList) {
  const wordSet = new Set(wordList);
  if (!wordSet.has(endWord)) return 0;

  const queue = [[beginWord, 1]]; // Queue stores [word, currentLength]
  const visited = new Set([beginWord]);

  while (queue.length > 0) {
    const [word, len] = queue.shift();
    if (word === endWord) return len;

    // Try mutating each character position
    for (let i = 0; i < word.length; i++) {
      for (let c = 97; c <= 122; c++) { // 'a' to 'z'
        const newWord = word.slice(0, i) + String.fromCharCode(c) + word.slice(i + 1);
        if (wordSet.has(newWord) && !visited.has(newWord)) {
          visited.add(newWord);
          queue.push([newWord, len + 1]);
        }
      }
    }
  }
  return 0;
  // Time Complexity: O(M^2 * N) - M is word length, N is words count
  // Space Complexity: O(M * N) - storage of words in structures
}

function climbStairs(n) {
  if (n <= 2) return n;
  let first = 1;
  let second = 2;
  for (let i = 3; i <= n; i++) {
    const third = first + second;
    first = second;
    second = third;
  }
  return second;
  // Time Complexity: O(N) - loop from 3 to N
  // Space Complexity: O(1) - space optimized variables
}

function coinChange(coins, amount) {
  // Initialize dp array with value greater than amount
  const dp = new Array(amount + 1).fill(amount + 1);
  dp[0] = 0; // Base case: 0 coins needed for amount 0

  for (let i = 1; i <= amount; i++) {
    for (let coin of coins) {
      if (i - coin >= 0) {
        dp[i] = Math.min(dp[i], dp[i - coin] + 1);
      }
    }
  }
  return dp[amount] > amount ? -1 : dp[amount];
  // Time Complexity: O(Amount * C) - where C is number of coins
  // Space Complexity: O(Amount) - size of dp array
}

function minDistance(word1, word2) {
  const m = word1.length;
  const n = word2.length;
  const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));

  // Base cases: distance between string and empty string
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;

  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      if (word1[i - 1] === word2[j - 1]) {
        dp[i][j] = dp[i - 1][j - 1]; // No edit operation required
      } else {
        dp[i][j] = Math.min(
          dp[i - 1][j] + 1,    // Deletion
          dp[i][j - 1] + 1,    // Insertion
          dp[i - 1][j - 1] + 1 // Replacement
        );
      }
    }
  }
  return dp[m][n];
  // Time Complexity: O(M * N) - nested loop on string dimensions
  // Space Complexity: O(M * N) - matrix table size
}

function fib(n) {
  if (n <= 1) return n;
  // Helper with memoization cache map
  const memo = new Map();
  function solve(x) {
    if (x <= 1) return x;
    if (memo.has(x)) return memo.get(x);
    const val = solve(x - 1) + solve(x - 2);
    memo.set(x, val);
    return val;
  }
  return solve(n);
  // Time Complexity: O(N) - visits each state once due to cache
  // Space Complexity: O(N) - recursion depth + map space
}

function generateParenthesis(n) {
  const result = [];

  function backtrack(currentStr, openCount, closeCount) {
    // Base case: used all parentheses
    if (currentStr.length === n * 2) {
      result.push(currentStr);
      return;
    }

    // Add open parenthesis if available
    if (openCount < n) {
      backtrack(currentStr + '(', openCount + 1, closeCount);
    }
    // Add close parenthesis if valid
    if (closeCount < openCount) {
      backtrack(currentStr + ')', openCount, closeCount + 1);
    }
  }

  backtrack('', 0, 0);
  return result;
  // Time Complexity: O(4^N / sqrt(N)) - Catalan number combinations
  // Space Complexity: O(N) - call stack recursion depth limit
}

function merge(nums1, m, nums2, n) {
  let p1 = m - 1;
  let p2 = n - 1;
  let p = m + n - 1; // End index of nums1

  while (p2 >= 0) {
    // Compare from the back
    if (p1 >= 0 && nums1[p1] > nums2[p2]) {
      nums1[p] = nums1[p1];
      p1--;
    } else {
      nums1[p] = nums2[p2];
      p2--;
    }
    p--;
  }
  // Time Complexity: O(M + N) - single pass merge
  // Space Complexity: O(1) - in-place merge, no extra array
}

function mergeIntervals(intervals) {
  if (intervals.length <= 1) return intervals;

  // Sort intervals by start time
  intervals.sort((a, b) => a[0] - b[0]);

  const merged = [intervals[0]];
  for (let i = 1; i < intervals.length; i++) {
    const current = intervals[i];
    const lastMerged = merged[merged.length - 1];

    // Overlap exists if current start is <= last merged end
    if (current[0] <= lastMerged[1]) {
      lastMerged[1] = Math.max(lastMerged[1], current[1]);
    } else {
      merged.push(current);
    }
  }
  return merged;
  // Time Complexity: O(N log N) - due to sorting
  // Space Complexity: O(N) - return array size or O(log N) sorting stack
}

function search(nums, target) {
  let left = 0;
  let right = nums.length - 1;
  while (left <= right) {
    // Avoid overflow in languages with fixed int sizing
    const mid = left + Math.floor((right - left) / 2);
    if (nums[mid] === target) return mid;
    if (nums[mid] < target) {
      left = mid + 1;
    } else {
      right = mid - 1;
    }
  }
  return -1; // Target not found
  // Time Complexity: O(log N) - halves space at each step
  // Space Complexity: O(1) - primitive variables only
}

function searchRotated(nums, target) {
  let left = 0;
  let right = nums.length - 1;
  while (left <= right) {
    const mid = left + Math.floor((right - left) / 2);
    if (nums[mid] === target) return mid;

    // Check if left half is sorted
    if (nums[left] <= nums[mid]) {
      if (nums[left] <= target && target < nums[mid]) {
        right = mid - 1;
      } else {
        left = mid + 1;
      }
    } else { // Right half must be sorted
      if (nums[mid] < target && target <= nums[right]) {
        left = mid + 1;
      } else {
        right = mid - 1;
      }
    }
  }
  return -1;
  // Time Complexity: O(log N) - binary search partitions
  // Space Complexity: O(1) - index counters
}

function findMedianSortedArrays(nums1, nums2) {
  if (nums1.length > nums2.length) return findMedianSortedArrays(nums2, nums1);
  const x = nums1.length;
  const y = nums2.length;
  let left = 0, right = x;

  while (left <= right) {
    const partitionX = left + Math.floor((right - left) / 2);
    const partitionY = Math.floor((x + y + 1) / 2) - partitionX;

    const maxLeftX = partitionX === 0 ? -Infinity : nums1[partitionX - 1];
    const minRightX = partitionX === x ? Infinity : nums1[partitionX];

    const maxLeftY = partitionY === 0 ? -Infinity : nums2[partitionY - 1];
    const minRightY = partitionY === y ? Infinity : nums2[partitionY];

    if (maxLeftX <= minRightY && maxLeftY <= minRightX) {
      if ((x + y) % 2 === 0) {
        return (Math.max(maxLeftX, maxLeftY) + Math.min(minRightX, minRightY)) / 2;
      } else {
        return Math.max(maxLeftX, maxLeftY);
      }
    } else if (maxLeftX > minRightY) {
      right = partitionX - 1;
    } else {
      left = partitionX + 1;
    }
  }
  return 0;
  // Time Complexity: O(log(min(M, N))) - binary search on smaller array
  // Space Complexity: O(1) - pointer boundaries
}

function isValid(s) {
  const stack = [];
  const bracketMap = { ')': '(', '}': '{', ']': '[' };

  for (let char of s) {
    if (char === '(' || char === '{' || char === '[') {
      stack.push(char);
    } else {
      const top = stack.pop();
      if (top !== bracketMap[char]) return false;
    }
  }
  return stack.length === 0;
  // Time Complexity: O(N) - single pass scan
  // Space Complexity: O(N) - stack storage for characters
}

class MinStack {
  constructor() {
    this.stack = []; // Stores elements as [val, minAtThisState]
  }
  push(val) {
    if (this.stack.length === 0) {
      this.stack.push([val, val]);
    } else {
      const currentMin = this.stack[this.stack.length - 1][1];
      this.stack.push([val, Math.min(val, currentMin)]);
    }
  }
  pop() {
    this.stack.pop();
  }
  top() {
    return this.stack[this.stack.length - 1][0];
  }
  getMin() {
    return this.stack[this.stack.length - 1][1];
  }
  // Time Complexity: O(1) for all operations
  // Space Complexity: O(N) - stores min states
}

function groupAnagrams(strs) {
  const map = new Map();
  for (let str of strs) {
    // Sort characters to create a unique signature key
    const sortedKey = str.split('').sort().join('');
    if (!map.has(sortedKey)) {
      map.set(sortedKey, []);
    }
    map.get(sortedKey).push(str);
  }
  return Array.from(map.values());
  // Time Complexity: O(N * K log K) - N strings of max length K sorted
  // Space Complexity: O(N * K) - storage in hash map
}

function topKFrequent(nums, k) {
  const freqMap = new Map();
  for (let num of nums) freqMap.set(num, (freqMap.get(num) || 0) + 1);

  // Bucket sort: index represents frequency
  const buckets = Array.from({ length: nums.length + 1 }, () => []);
  for (let [num, freq] of freqMap) {
    buckets[freq].push(num);
  }

  const result = [];
  // Collect from right to left (highest frequencies first)
  for (let i = buckets.length - 1; i >= 0 && result.length < k; i--) {
    if (buckets[i].length > 0) {
      result.push(...buckets[i]);
    }
  }
  return result.slice(0, k);
  // Time Complexity: O(N) - bucket sort linear scan
  // Space Complexity: O(N) - map and bucket structures
}

// Optimal approach uses two heaps: Max-Heap (small half) & Min-Heap (large half)
// Since JS has no native Heap, we use a sorted array wrapper for demonstration
class MedianFinder {
  constructor() {
    this.store = [];
  }
  addNum(num) {
    // Binary search insertion to keep array sorted (mimics heaps)
    let left = 0, right = this.store.length;
    while (left < right) {
      const mid = Math.floor((left + right) / 2);
      if (this.store[mid] < num) left = mid + 1;
      else right = mid;
    }
    this.store.splice(left, 0, num);
  }
  findMedian() {
    const len = this.store.length;
    if (len % 2 === 0) {
      return (this.store[len / 2 - 1] + this.store[len / 2]) / 2;
    } else {
      return this.store[Math.floor(len / 2)];
    }
  }
  // Note: Heap implementation would give: addNum O(log N), findMedian O(1)
  // Sorted Array implementation gives: addNum O(N), findMedian O(1)
}
